import java.rmi.*;

// Remote interface extending Remote
public interface CalculatorRemote extends Remote {
 // All methods must throw RemoteException
 public int add(int a, int b) throws RemoteException;
 public int subtract(int a, int b) throws RemoteException;
 public int multiply(int a, int b) throws RemoteException;
 public int divide(int a, int b) throws RemoteException;
}

import java.rmi.*;
import java.rmi.server.*;

public class CalculatorImpl extends UnicastRemoteObject 
 implements CalculatorRemote {

 // Constructor must throw RemoteException
 public CalculatorImpl() throws RemoteException {
 super();
 }

 // Implementation of remote methods
 public int add(int a, int b) throws RemoteException {
 return a + b;
 }

 public int subtract(int a, int b) throws RemoteException {
 return a - b;
 }

 public int multiply(int a, int b) throws RemoteException {
 return a * b;
 }

 public int divide(int a, int b) throws RemoteException {
 if (b == 0) throw new RemoteException("Division by zero");
 return a / b;
 }
}

import java.rmi.*;
import java.rmi.registry.*;

public class RMIServer {
 public static void main(String[] args) {
 try {
 // Create remote object
 CalculatorImpl calc = new CalculatorImpl();

 // Register with RMI registry
 Naming.rebind("rmi://localhost:1099/CalculatorService", calc);

 System.out.println("Server is ready...");

 } catch (Exception e) {
 System.err.println("Server exception: " + e.getMessage());
 e.printStackTrace();
 }
 }
}

import java.rmi.*;

public class RMIClient {
 public static void main(String[] args) {
 try {
 // Lookup remote object
 CalculatorRemote calc = (CalculatorRemote)
 Naming.lookup("rmi://localhost:1099/CalculatorService");

 // Call remote methods
 System.out.println("Addition: " + calc.add(10, 5));
 System.out.println("Subtraction: " + calc.subtract(10, 5));
 System.out.println("Multiplication: " + calc.multiply(10, 5));
 System.out.println("Division: " + calc.divide(10, 5));

 } catch (Exception e) {
 System.err.println("Client exception: " + e.getMessage());
 e.printStackTrace();
 }
 }
}

// Step 1: Compile Java files
javac CalculatorRemote.java
javac CalculatorImpl.java
javac RMIServer.java
javac RMIClient.java

// Step 2: Generate Stub and Skeleton using rmic
rmic CalculatorImpl

// Step 3: Start RMI Registry (in separate terminal)
start rmiregistry

// Step 4: Run Server (in separate terminal)
java RMIServer

// Step 5: Run Client (in separate terminal)
java RMIClient

// Expected Output:
// Server: Server is ready...
// Client: Addition: 15
// Subtraction: 5
// Multiplication: 50
// Division: 2
